say_hello()

def timer(func):
    def wrapper():
        import time
        start = time.time()
        func()
        end = time.time()
        print(f'Took {end - start:.4f} seconds')
    return wrapper

@timer
def slow_function():
    total = 0
    for i in range(1000000):
        total += i
    print(f'Sum: {total}')

slow_function()

from functools import wraps

def my_decorator(func):
    @wraps(func)
    def wrapper():
        print('Before')
        func()
        print('After')
    return wrapper

@my_decorator
def greet():
    '''Says hello to the world.'''
    print('Hello!')

print(greet.__name__)
print(greet.__doc__)
